    private void processTransaction(TransactionType type) {
        final BigDecimal amount = parseAmount();
        if (amount == null) {
            return;
        }

        setProcessing(true);
        statusView.setText("");

        executor.execute(() -> {
            TransactionResult result;
            try {
                result = TransactionProcessor.process(account, type, amount);
            } catch (Exception e) {
                result = TransactionResult.failure("Transaction failed.");
            }

            TransactionResult finalResult = result;
            mainHandler.post(() -> {
                setProcessing(false);
                if (finalResult.success) {
                    renderBalance();
                    statusView.setText(finalResult.message);
                    Toast.makeText(BankingActivity.this, finalResult.message, Toast.LENGTH_SHORT).show();
                    amountInput.setText("");
                } else {
                    statusView.setText(finalResult.message);
                    Toast.makeText(BankingActivity.this, finalResult.message, Toast.LENGTH_SHORT).show();
                }
            });
        });
    }

    @Nullable
    private BigDecimal parseAmount() {
        String raw = amountInput.getText() == null ? "" : amountInput.getText().toString().trim();
        if (raw.isEmpty()) {
            Toast.makeText(this, "Enter an amount.", Toast.LENGTH_SHORT).show();
            return null;
        }

        try {
            BigDecimal amount = new BigDecimal(raw).setScale(2, RoundingMode.HALF_UP);
            if (amount.compareTo(BigDecimal.ZERO) <= 0) {
                Toast.makeText(this, "Amount must be greater than zero.", Toast.LENGTH_SHORT).show();
                return null;
            }
            return amount;
        } catch (Exception e) {
            Toast.makeText(this, "Invalid amount.", Toast.LENGTH_SHORT).show();
            return null;
        }
    }

