    enum TransactionType {
        DEPOSIT,
        WITHDRAW,
        TRANSFER
    }

    static class TransactionProcessor {

        static TransactionResult process(Account account, TransactionType type, BigDecimal amount) {
            synchronized (account) {
                switch (type) {
                    case DEPOSIT:
                        account.deposit(amount);
                        return TransactionResult.success("Deposit successful.");
                    case WITHDRAW:
                        if (!account.withdraw(amount)) {
                            return TransactionResult.failure("Insufficient funds.");
                        }
                        return TransactionResult.success("Withdrawal successful.");
                    case TRANSFER:
                        if (!account.withdraw(amount)) {
                            return TransactionResult.failure("Insufficient funds.");
                        }
                        return TransactionResult.success("Transfer successful.");
                    default:
                        return TransactionResult.failure("Unsupported transaction.");
                }
            }
        }
    }

    static class TransactionResult {
        final boolean success;
        final String message;

        private TransactionResult(boolean success, String message) {
            this.success = success;
            this.message = message;
        }

        static TransactionResult success(String message) {
            return new TransactionResult(true, message);
        }

        static TransactionResult failure(String message) {
            return new TransactionResult(false, message);
        }
    }

    static class Account {
        private final String displayName;
        private BigDecimal balance;

        Account(String displayName, BigDecimal initialBalance) {
            this.displayName = displayName;
            this.balance = normalize(initialBalance);
        }

        String getDisplayName() {
            return displayName;
        }

        BigDecimal getBalance() {
            return balance;
        }

        void deposit(BigDecimal amount) {
            balance = normalize(balance.add(amount));
        }

        boolean withdraw(BigDecimal amount) {
            if (balance.compareTo(amount) < 0) {
                return false;
            }
            balance = normalize(balance.subtract(amount));
            return true;
        }

        private BigDecimal normalize(BigDecimal value) {
            return value.setScale(2, RoundingMode.HALF_UP);
        }
    }
